local TS = game:GetService("TweenService") local RepStorage = game:GetService("ReplicatedStorage") local event local function newins(name, instancee, parent) local index = Instance.new(instancee) index.Name = name index.Parent = parent return index end local function init() event = newins("Animate", "BindableEvent", RepStorage) endlocal function eventfn(animinfo) local shouldRepeat = select(1, animinfo) local goal = select(2, animinfo) local duration = select(3, animinfo)  local target = goal.Instance  local tweenInfo = TweenInfo.new(duration) local tween = TS:Create(target, tweenInfo, goal.Properties) tween:Play() if shouldRepeat then tween.Completed:Connect(function() tween:Play() end) end endevent.Event:Connect(eventfn) return init
    
